// Récupérer tous les éléments
const items = $input.all();

// Maps pour organiser les données
const foldersMap = new Map();
const filesMap = new Map();
const childrenMap = new Map(); // parentId -> [childIds]

// Première passe : classifier tous les éléments
for (const item of items) {
  const data = item.json;
  const id = data.id;
  const name = data.name;
  const mimeType = data.mimeType;
  const parentId = data.parents && data.parents.length > 0 ? data.parents[0] : 'root';

  // Initialiser la liste des enfants pour ce parent
  if (!childrenMap.has(parentId)) {
    childrenMap.set(parentId, []);
  }
  childrenMap.get(parentId).push(id);

  if (mimeType === 'application/vnd.google-apps.folder') {
    foldersMap.set(id, {
      id: id,
      nom: name,
      type: 'dossier',
      parentId: parentId
    });
  } else {
    filesMap.set(id, {
      id: id,
      nom: name,
      type: 'fichier',
      mimeType: mimeType,
      parentId: parentId
    });
  }
}

// Fonction récursive pour construire l'arborescence d'un dossier
function buildFolderContent(folderId) {
  const result = {
    sousDossiers: [],
    fichiers: []
  };

  const children = childrenMap.get(folderId) || [];

  for (const childId of children) {
    if (foldersMap.has(childId)) {
      const folder = foldersMap.get(childId);
      const content = buildFolderContent(childId);
      result.sousDossiers.push({
        id: folder.id,
        nom: folder.nom,
        type: 'dossier',
        sousDossiers: content.sousDossiers,
        fichiers: content.fichiers
      });
    } else if (filesMap.has(childId)) {
      const file = filesMap.get(childId);
      result.fichiers.push({
        id: file.id,
        nom: file.nom,
        type: 'fichier',
        mimeType: file.mimeType
      });
    }
  }

  return result;
}

// Trouver les éléments racine (parent = 'root' ou parent non trouvé)
const rootFolders = [];
const rootFiles = [];

for (const [id, folder] of foldersMap) {
  if (folder.parentId === 'root' || !foldersMap.has(folder.parentId)) {
    const content = buildFolderContent(id);
    rootFolders.push({
      id: folder.id,
      nom: folder.nom,
      type: 'dossier',
      sousDossiers: content.sousDossiers,
      fichiers: content.fichiers
    });
  }
}

for (const [id, file] of filesMap) {
  if (file.parentId === 'root' || !foldersMap.has(file.parentId)) {
    rootFiles.push({
      id: file.id,
      nom: file.nom,
      type: 'fichier',
      mimeType: file.mimeType
    });
  }
}

// Construire la réponse finale
const response = {
  success: true,
  timestamp: new Date().toISOString(),
  statistiques: {
    totalDossiers: foldersMap.size,
    totalFichiers: filesMap.size,
    dossiersRacine: rootFolders.length,
    fichiersRacine: rootFiles.length
  },
  arborescence: {
    dossiers: rootFolders,
    fichiers: rootFiles
  }
};

return [{ json: response }];
